/*【夏の白昼夢▪】作者：易碎蝶*/
/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */

@import url("https://fontsapi.zeoseven.com/309/main/result.css");

body {
    font-family: "KingHwaOldSong";
    font-weight: normal;
    /* 添加 font-feature-settings: "hwid"; 以启用这款字体支持的 OpenType 等宽变化字形 */
}

/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 77px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/3WQ54VZF/Image-1515849942941351.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 10px;

    /* 层级控制 */
    z-index: 3004;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}

/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/nrWVRntK/retouch-2025062711174872.jpg'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 40px;
  height: 40px;
  background: transparent url('https://i.postimg.cc/NF4SFF5B/Image-1516472624678311.png') center/cover no-repeat;
  border: none;
  border-radius: 0;
  box-shadow: none;
  cursor: ew-resize;
  position: relative;
  z-index: 1;
}

/*——————最新消息箭头图标替换——————*/
/* 隐藏原有字体图标 */
.fa-chevron-right:before,
.fa-chevron-left:before {
  content: "" !important;
}

/* 左箭头图片容器 */
.fa-chevron-left {
  display: inline-block;
  width: 90px; /* 图片宽度 */
  height: 30px; /* 图片高度 */
  background: url('https://i.postimg.cc/NF4SFF5B/Image-1516472624678311.png') center/contain no-repeat;
  /* ↑ 替换为您的左箭头图片链接 ↑ */
}

/* 右箭头图片容器 */
.fa-chevron-right {
  display: inline-block;
  width: 90px; /* 图片宽度 */
  height: 30px; /* 图片高度 */
  background: url('https://i.postimg.cc/NF4SFF5B/Image-1516472624678311.png') center/contain no-repeat;
  /* ↑ 替换为您的右箭头图片链接 ↑ */
}

.swipes-counter {
  color: var(--SmartThemeBodyColor);
  font-size: 10px;
  /* 位置调整 */
  margin: var(--counter-vertical, 0) var(--counter-horizonta, 0); /* 垂直 水平 */
  /* 或使用绝对定位 */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */

  padding: 0 50px;
  font-family: var(--mainFontFamily);
  font-weight: 40;
  align-self: center;
  min-width: 100px;
  display: flex;
  justify-content: center;
  margin-bottom: var(--swipeCounterMargin);
  height: var(--swipeCounterHeight);
}

.fa-arrow-right:before {
    display: none !important;
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -140px; /* 上层装饰层【上下】(负值表示向上) */
  left: -18px; /* 上层装饰层【左右】 */
  width: 375px; /* 调整上层装饰层的【宽度/大小】 */
  height: 437px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/HnP740Nx/Image-1512557547559924.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 40; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -155px; /* 下层装饰层【上下】(负值表示向下) */
  right: -18px; /* 下层装饰层【左右】 */
  width: 376px; /* 调整下层装饰层的【宽度/大小】 */
  height: 278px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('https://i.postimg.cc/yxNZZpvt/Image-1512554298547078.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 42; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */
    --top-padding:4rem; /* 气泡顶部留白 */
    --bottom-padding: 4.3rem; /* 气泡底部留白 */
    --left-padding: 0.3rem; /* 气泡左边距 */
    --right-padding: 0.6rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}




/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  max-width: 340px; /* 气泡最大宽度 */
  width: 500%; /* 宽度适配 */
  margin: 190px auto 130px; /* 气泡间距：上 130px | 左右自动 | 下 90px */
  border-radius: 0px;

  /* 主色调渐变：淡绿到奶油白 */
  background: linear-gradient(
    145deg, 
    rgba(255, 255, 255, 1) 0%,  /* 淡绿基底 */
    rgba(255, 255, 255, 1) 70%   /* 奶油白过渡 */
  );

  /* 三层浅色描边 */
  box-shadow: 
    0 0 0 2px rgba(255, 255, 255, 0.9),  /* 内层：柔光白描边 */
    0 0 0 2px rgba(198, 217, 163, 0.8),  /* 中层：淡绿 (#c6d9a3) 光晕 */
    0 0 0 0px rgba(252, 171, 215, 0.6),  /* 外层：粉紫 (#fcabd7) 柔光 */
    inset 2px 1px 10px rgba(255, 172, 173, 0.35); /* 内陷阴影：粉红 (#ffacad) 柔影 */
}

#chat {
  max-height: calc(100vh - calc(var(--topBarBlockSize) + var(--bottomFormBlockSize)));
  overflow-x: hidden;
  padding-bottom: 0;
  overflow-y: scroll;
  display: flex;
  bottom: 10px;
  position: relative; /* 为伪元素定位做准备 */

  /* 内发光：淡绿柔光 + 粉红底影 */
  box-shadow: 
    inset 0 9px 120px rgba(198, 217, 163, 0.08), /* 顶部：淡绿 (#c6d9a3) 弥散光 */
    inset 0 0px 3px rgba(255, 172, 173, 0);   /* 底部：粉红 (#ffacad) 细柔影 */



/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -100px;           /* 【控制头像在气泡上方的位置】 */
  left: 24%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: 1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 95px;           /* 头像宽度 */
  height: 108px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 3px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(0deg); /* 顺时针旋转 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 楼层显示
 * ============================================== */
.mes .mesIDDisplay {
    position: fixed;  
    top: 200;           
    left: 5%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: 27px; /* 【楼层上下】 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    color: #AD9FA3; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */
.mes_block {
  position: relative; 
}

.mes_block::before {
  content: ""; 
  display: block;
  height: 50px; /* 【上下/留白】 */
}

.mes_block .ch_name {
  max-width: calc(100% - 105px);
  min-height: 50px;
  position: absolute; 
  top: 0.5; /* 顶部紧贴 */
  left: 14px; /*【 左侧偏移】 */
  right: -50px; /* 【右侧留白】 */
}
}
/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 0.5;
  font-size: calc(var(--mainFontSize) * 0.9);
  font-weight: 600;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #BFC8BA;
  --counter-color: #BFC8BA;
}

/* 单独控制计时器 */
.mes .mes_timer {
  /* 位置调整 */
  top: var(--timer-top, 138px);  /* 【计时器上下】 */
  left: var(--timer-left, 130%);/*【计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));
  /* 颜色控制 */
  color: var(--timer-color, #6F7D88);
}


/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  /* 位置调整 */
  top: var(--counter-top, 138px); /* 【字符上下】 */
  left: var(--counter-left, 52%);/* 【字符左右】 */
  transform: translateX(var(--counter-translate, -0%));

  /* 颜色控制 */
  color: var(--counter-color, #BFC8BA);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整
 * ============================================== */
.mes_reasoning_header {
  /* 定位控制 */
  position: absolute;
  z-index: 9999;
  top: -40px;       /* 【垂直位置】 */
  left: 70%;        /* 【水平位置】 */
  transform: translateX(-50%);
/* 白日梦主题 - 日间模式 */
/* 主色: 白色和淡绿色 | 辅助色: 图片中的粉绿色系 */

/* 文字颜色 - 日间深灰文字 */
color: #BFC8BA;   /* 调整为带绿调的深灰，更符合自然主题 */

/* 基础属性 - 保持原有交互特性 */
cursor: pointer;
user-select: none;
font-size: calc(var(--mainFontSize) * 0.85);
opacity: 0.8;
transition: all 0.3s ease;

/* 三层描边效果 - 白日梦主题风格 */
padding: 4px 10px;
background: rgba(250, 255, 245, 0.7); /* 主背景: 极淡绿色半透明 */
border-radius: 6px;
box-shadow: 
  inset 1px 1px 2px rgba(198, 217, 163, 0.4),  /* 内陷阴影: 浅绿色柔光效果 */
  0 0 0 1px rgba(255, 255, 255, 0.9),          /* 第一层描边: 亮白高光 */
  0 0 0 2px rgba(255, 172, 173, 0.2),          /* 第二层描边: 粉红色柔边 */
  0 2px 4px rgba(120, 120, 120, 0.05);         /* 外阴影: 轻微深度感 */
border: 1px solid #e6f0da;                     /* 边框: 淡绿色细线 */
position: relative;
}

.mes_reasoning {
display: block;
border-left: 1px solid #c6d9a3;              /* 左侧边框: 图片中的浅绿色 */
border-radius: 4px;
padding: 0px;
padding-left: 28px;
margin: 20px 0;
overflow-y: auto;
color: #556655;                             /* 文字颜色: 带绿调的深灰 */
background: rgba(252, 251, 245, 0.8);       /* 背景: 暖白色半透明 */
box-shadow: 
  inset 2px 0 4px rgba(252, 171, 215, 0.2), /* 内阴影: 浅粉色柔光 */
  0 2px 6px rgba(150, 150, 150, 0.08);      /* 外阴影: 柔和投影 */
transition: all 0.3s ease;
}
.mes_reasoning_header_title {
position: relative;
display: inline-block;
top: 0px;
left: -8px;
}
}

