    padding: 2px 6px;
    cursor: pointer;
    margin: 5px 0;
    transition: 0.3s;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    box-shadow: 
        /* 描边结构 */
        0 0 0 1px #ffffff,          /* 白色外描边 */
