    box-shadow: 
        0 0 0 1px #ffffff,
        0 0 0 2px #d0e2bb,           /* 浅绿色悬停描边 */
        0 0 0 3px #ffffff,
        inset 1px 1px 2px rgba(198, 217, 163, 0.4),
        inset -1px -1px 2px rgba(255, 255, 255, 0.9),
        1px 1px 3px rgba(198, 217, 163, 0.2); /* 浅绿外阴影 */
