    box-shadow: 
        0 0 0 1px #ffffff,
        0 0 0 2px #b1c993,           /* 深绿色按压描边 */
        0 0 0 3px #ffffff,
        inset 2px 2px 3px rgba(177, 201, 147, 0.4), /* 增强内阴影 */
