/*——————文本编辑框美化——————*/
.reasoning_edit_textarea, .edit_textarea {
    padding: 15px 15px;  /* 内容内边距 */
    margin: 0;  /* 外边距清零 */
    width: 100%;  /* 宽度100%填充 */
    max-height: 75vh;  /* 最大高度 */
    max-height: 75dvh;  /* 动态高度支持 */
    outline: none;  /* 移除默认outline */

    background: #FFFFFF;  /* 纯白底色（日间模式） */
    border: 2px solid #FFFFFF;  /* 第一层：纯白描边（增强纯净感） */
    outline: 3px solid #c6d9a3;  /* 第二层：淡绿描边（辅助色#c6d9a3） */
    border-radius: 8px;  /* 圆角统一 */
    box-shadow: none;  /* 清除默认阴影 */
    color: #4A4A4A;  /* 深灰文字（保证日间可读性） */
    font-size: 16px;  /* 字号保持 */
    line-height: 1.6;  /* 行高保持 */
    font-family: 'Helvetica Neue', sans-serif;  /* 字体保持 */

    transition: border-color 0.3s ease, 
                box-shadow 0.3s ease;  /* 平滑过渡效果 */

    &:focus {
        box-shadow: 
            inset 2px 2px 4px rgba(200,215,208,0.6),  /* 左上淡绿内阴影（#c6d9a3的浅色变体） */
            inset -2px -2px 4px rgba(255,172,173,0.3),  /* 右下粉红内阴影（#ffacad的浅色变体） */
            0 0 0 3px #FFFFFF,  /* 维持白色描边层 */
            0 0 12px rgba(252,171,215,0.4);  /* 外部粉红光晕（#fcabd7的浅色变体） */
    }

    &::placeholder {
        color: #B8C6B0;  /* 灰绿占位符（与淡绿辅助色协调） */
        opacity: 0.8;  /* 透明度保持 */
    }

    scrollbar-width: thin;  /* 细滚动条 */
    scrollbar-color: #c6d9a3 #F0F4EB;  /* 滚动条：淡绿滑块+浅绿轨道 */

    &::-webkit-scrollbar {
        width: 6px;  /* 滚动条宽度 */
        background: #F0F4EB;  /* 滚动轨道浅绿色（#c6d9a3的浅色变体） */
    }

    &::-webkit-scrollbar-thumb {
        background: #c6d9a3;  /* 滚动条淡绿色（辅助色） */
        border-radius: 3px;  /* 匹配圆角主题 */
    }
}

/*————弹窗美化————*/
/* 基础容器样式 */
#toast-container.toast-bottom-center>div,
#toast-container.toast-top-center>div {
  width: 300px;
  margin-left: auto;
  margin-right: auto;
}

/* 全局盒模型设置 */
#toast-container * {
  -moz-box-sizing: border-box;
  -webkit-box-sizing: border-box;
  box-sizing: border-box;
}

/* 标题字体 */
.toast-title {
  font-weight: 700;
}

/* 弹窗基础样式 */
.toast {
  position: relative;
  padding: 15px 20px 15px 65px; 
  min-height: 60px;
  background: rgba(248,248,248,1); 
  border-radius: 8px;
}

/* 图片容器 */
.toast::before {
  content: "";
  position: absolute;
  left: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 36px;
  height: 36px;
  background: 
    url("https://i.postimg.cc/xdwWFBwD/Image-1516468205267926.png")
    center/contain no-repeat;
}

/* 成功弹窗图片 */
.toast-success::before {
  background-image: 
    url("https://i.postimg.cc/xdwWFBwD/Image-1516468205267926.png");
}

/* 错误弹窗图片 */
.toast-error::before {
  background-image: 
    url("https://i.postimg.cc/85Lq8tGF/Image-1516470413697157.png");
}

/* 消息内容区 */
.toast-message {
  line-height: 1.4;
  padding-top: 2px;
  font-size: 12px;
}

/* 文字颜色修复 */
#toast-container * {
    color: #5c5c5c !important;
}

/* 增强标题可读性 */
.toast-title {
    color: #4a4a4a !important;
    text-shadow: 0 1px 0 rgba(255, 255, 255, 0.5); 
}

/* 调整消息文字 */
.toast-message {
    color: #5c5c5c !important;
    opacity: 0.9; 
}
/*隐藏原有图标*/
#toast-container>.toast-success, 
#toast-container>.toast-error {
    background-image: none !important;
}

/*————加载页面美化————*/
#load-spinner {
    background: url("https://i.postimg.cc/7hDjq0PK/Image-1516466222927311.png") no-repeat center center;
    background-size: contain; 
}

/* 隐藏原有旋转图标 */
#load-spinner::before,
#load-spinner::after {
    display: none;
}

